import React, { useEffect, useState } from 'react'
import { useNavigate } from 'react-router-dom';
import { CCol, CForm, CButton } from "@coreui/react";
import FormInput from 'src/utils/FormInput';
import { createDepartment, fetchDepartmentById, updateDepartment } from 'src/components/services/CareerApi';
import authService from 'src/auth/auth.service';
import GoBackComponent from 'src/utils/GoBackComponent';

function departmentForm(props) {
    const { type, id } = props;
    const [formData, setFormData] = useState({ name: "" });
    const [errors, setErrors] = useState({});
    const [errorMessage, setErrorMessage] = useState("");
    const [userData] = useState(authService.getUserDetailsFromLocalStorage())
    const navigate = useNavigate();

    useEffect(() => {
        if (type === "UPDATE") {
            fetchDepartmentDataById(id);
        }
    }, [])

    const handleChange = (event) => {
        setFormData({ ...formData, [event.target.name]: event.target.value.trimStart().replace(/  +/g, ' ') });
    };


    const fetchDepartmentDataById = async (id) => {
        let response = await fetchDepartmentById(id);
        if (response?.code === 200) {
            let data = {
                name: response?.results?.name
            }
            setFormData(data);
        }


    }

    const validateForm = () => {
        let errors = {};
        let formIsValid = true;
        if (formData.name === "") {
            errors['name'] = "Please enter department name";
            formIsValid = false;
        }
        setErrors(errors);
        setTimeout(() => {
            setErrors({});
        }, 2000);
        return formIsValid;
    }

    const handleSubmit = async (event) => {
        event.preventDefault();
        if (validateForm()) {
            let postData = {
                name: formData?.name?.trim()
            }
            let category = {};
            if (type === "CREATE") {
                postData.createdBy = userData?.name;
                category = await createDepartment(postData);
            } else {
                postData.id = id;
                category = await updateDepartment(postData);
            }
            if (category?.code === 201 || category?.code === 202) {
                navigate('/career/department');
            }
            if (category?.code === 409) {
                setErrorMessage(category?.message);
            }
            setTimeout(() => {
                setErrorMessage("");
            }, 2000);
        }
    };


    return (
        <>
            <GoBackComponent goBackData={"career/department"} />
            <div className='customContainer'>
                <CForm className="row g-3">
                    <CCol md={8}>
                        <FormInput
                            value={formData.name}
                            label={"Department Name"}
                            required
                            name={"name"}
                            onChange={handleChange}
                            error={errors['name']}
                        />
                        {errorMessage && <span style={{ color: "red" }}>{errorMessage}</span>}
                    </CCol>

                    <CCol md={12}>
                        <CButton color="primary" onClick={handleSubmit} className="d-block">
                            {props.type === "CREATE" ? "Create" : "Update"}
                        </CButton>
                    </CCol>
                </CForm>
            </div>
        </>
    )
}

export default departmentForm
